query:
UPDATE stocks 
SET ytdPerformance = ROUND((currentPrice - ytdStartPrice) / ytdStartPrice * 100, 2)
WHERE ticker IN ('ADEN.SW', 'AMGN') AND ytdStartPrice IS NOT NULL AND ytdStartPrice > 0;

